  // smin(A+C, B) - smin(A, B) --> select icmp slt A, B, C, 0
  // smax(A+C, B) - smax(A, B) --> select icmp sge A, B, C, 0
  // umin(A+C, B) - umin(A, B) --> select icmp ult A, B, C, 0
  // umax(A+C, B) - umax(A, B) --> select icmp uge A, B, C, 0
  // Also handle add(C, A) instead of add(A, C)
  if (Op0->hasOneUse() && Op1->hasOneUse()) {
    auto *Op0MinMax = dyn_cast<MinMaxIntrinsic>(Op0);
    if (Op0MinMax && Op0MinMax->getIntrinsicID() == MinMax->getIntrinsicID()) {
      Value *X0 = Op0MinMax->getLHS();
      Value *Y0 = Op0MinMax->getRHS();
      ConstantInt *C;
      // Case 1: Op0 = min/max(X+C, Y), Op1 = min/max(X, Y)
      if (Y0 == Y && match(X0, m_c_Add(m_Specific(X), m_Constant(C))) &&
          C->isPositive()) {
        ICmpInst::Predicate Pred;
        switch (MinMax->getIntrinsicID()) {
        case Intrinsic::smin: Pred = ICmpInst::ICMP_SLT; break;
        case Intrinsic::smax: Pred = ICmpInst::ICMP_SGE; break;
        case Intrinsic::umin: Pred = ICmpInst::ICMP_ULT; break;
        case Intrinsic::umax: Pred = ICmpInst::ICMP_UGE; break;
        default: return nullptr;
        }
        Value *Cmp = Builder.CreateICmp(Pred, X, Y);
        return SelectInst::Create(Cmp, C, Constant::getNullValue(Ty));
      }
      // Case 2: Op0 = min/max(Y, X+C), Op1 = min/max(Y, X)
      if (X0 == X && match(Y0, m_c_Add(m_Specific(Y), m_Constant(C))) &&
          C->isPositive()) {
        ICmpInst::Predicate Pred;
        switch (MinMax->getIntrinsicID()) {
        case Intrinsic::smin: Pred = ICmpInst::ICMP_SLT; break;
        case Intrinsic::smax: Pred = ICmpInst::ICMP_SGE; break;
        case Intrinsic::umin: Pred = ICmpInst::ICMP_ULT; break;
        case Intrinsic::umax: Pred = ICmpInst::ICMP_UGE; break;
        default: return nullptr;
        }
        Value *Cmp = Builder.CreateICmp(Pred, Y, X);
        return SelectInst::Create(Cmp, C, Constant::getNullValue(Ty));
      }
    }
  }

